const items = $input.all();
if (items.length === 0) throw new Error('Nenhuma conta retornada pela API');

let accounts = [], mapping = [];
const first = items[0]?.json || {};
const second = items.length >= 2 ? (items[1]?.json || {}) : {};

if (items.length === 1) {
  // Merge combineByPosition entregou 1 item com accounts e mapping juntos
  if (first.accounts) accounts = first.accounts;
  else if (Array.isArray(first)) accounts = first;
  else if (first.data) accounts = first.data;
  if (first.mapping) mapping = first.mapping;
  else if (first.data && !first.accounts) mapping = first.data;
} else {
  if (Array.isArray(first)) { accounts = first; }
  else if (first.accounts) { accounts = first.accounts; }
  else if (first.data) { accounts = first.data; }
  if (Array.isArray(second)) { mapping = second; }
  else if (second.mapping) { mapping = second.mapping; }
  else if (second.data) { mapping = second.data; }
}

if (accounts.length === 0) throw new Error('Lista de contas vazia');

const byId = {};
mapping.forEach(m => {
  const id = String(m.meta_account_id || '');
  byId[id] = m;
  byId['act_' + id] = m;
});

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toISOString().split('T')[0];

return accounts.map(a => {
  const id = String(a.id || ('act_' + (a.account_id || '')));
  const m = byId[id] || {};
  return { json: {
    account_id: id,
    account_name: a.name || a.account_name || id,
    client_id: m.client_id || null,
    owner_type: m.owner_type || 'adventure',
    _date: dateStr
  }};
});

// Cada item aqui é o output do GET Insights (1 item por conta)
// O n8n mantém pairedItem 1-para-1: podemos recuperar o item
// original do Code Merge via $('Code Merge').item
const items = $input.all();
const results = [];
const errors = [];

for (let i = 0; i < items.length; i++) {
  const insightsItem = items[i].json;

  // Recupera contexto da conta pelo pairedItem index
  let accountCtx = {};
  try {
    accountCtx = $('Code Merge').all()[i]?.json || {};
  } catch(e) {}

  const account_id   = accountCtx.account_id   || insightsItem.account_id   || null;
  const account_name = accountCtx.account_name || insightsItem.account_name || null;
  const client_id    = accountCtx.client_id    || null;
  const owner_type   = accountCtx.owner_type   || 'adventure';
  const date         = accountCtx._date        || new Date().toISOString().split('T')[0];

  // Se o GET Insights falhou (veio para error output)
  if (insightsItem.error || (insightsItem.statusCode && insightsItem.statusCode >= 400)) {
    errors.push({ account_id, error: insightsItem.error || 'HTTP ' + insightsItem.statusCode });
    continue;
  }

  // insights pode ser array vazio (sem veiculação)
  const rawIns = insightsItem.insights || insightsItem.data || [];
  const ins = Array.isArray(rawIns) ? (rawIns[0] || null) : rawIns;

  if (!ins) continue; // sem dados no período

  const spend       = ins.spend       != null ? parseFloat(ins.spend)        : null;
  const impressions = ins.impressions  != null ? parseInt(ins.impressions, 10) : null;
  const clicks      = ins.clicks       != null ? parseInt(ins.clicks, 10)     : null;

  // Soma conversões relevantes do array actions
  const CONV_TYPES = ['purchase','lead','complete_registration',
    'offsite_complete_registration_add_meta_leads','onsite_conversion.lead_grouped'];
  let conversions = null;
  if (Array.isArray(ins.actions)) {
    const sum = ins.actions
      .filter(a => CONV_TYPES.includes(a.action_type))
      .reduce((acc, a) => acc + parseInt(a.value || 0, 10), 0);
    if (sum > 0) conversions = sum;
  }

  const teveVeiculacao = (impressions > 0) || (spend > 0) || (clicks > 0);
  if (!teveVeiculacao) continue;

  results.push({
    json: {
      rows: [{ date, account_id, account_name, client_id, owner_type,
               spend, impressions, clicks, conversions }],
      _errors: errors
    }
  });
}

if (results.length === 0 && errors.length > 0) {
  return [{ json: { _no_data: true, _errors: errors } }];
}
if (results.length === 0) return [];
return results;

const results = $input.first()?.json?.all_results || [];
const errors = [];
const successes = [];
for (const r of results) {
  if (r._errors) errors.push(...r._errors);
  if (!r._no_data && r.rows) successes.push(...r.rows);
}
const today = new Date().toISOString().split('T')[0];
return [{ json: {
  processed: successes.length,
  errors_count: errors.length,
  errors,
  has_errors: errors.length > 0,
  run_date: today
}}];

