const s = $input.first()?.json || {};
const n = s.distinct_dates || 0;
const today = new Date().toISOString().split('T')[0];
if (n < 1) {
  return [{ json: { _skip_report: true, run_date: today, message: 'Sem dados no período' } }];
}
// Limita window de análise a 30 dias
const max = s.max_date || today;
const minDate = new Date(max);
minDate.setDate(minDate.getDate() - 29);
const min = s.min_date > minDate.toISOString().split('T')[0]
  ? s.min_date
  : minDate.toISOString().split('T')[0];
const title = 'Lara (Meta Ads) — ' + min + ' a ' + max;
return [{ json: { title, min_date: min, max_date: max, distinct_dates: n } }];

const res = $input.first()?.json || {};
const title = res.title || 'Lara (Meta Ads)';
const content = res.content || '';
const today = new Date().toISOString().split('T')[0];
const build = $('Build Report').first()?.json || {};
const min = build.min_date || '';
const max = build.max_date || '';
const cmoReport = { title: '[CMO] ' + title, content, report_type: 'meta_ads_daily', date: today, tags: ['meta_ads', 'lara', 'cmo'] };
const founderReport = { title: '[Founder] ' + title, content: content.slice(0, 3000), report_type: 'meta_ads_daily_summary', date: today, tags: ['meta_ads', 'lara', 'founder'] };
const memoryPayload = { agent: 'lara', date: today, period: min + ' a ' + max, insights: content.slice(0, 500), report_title: title };
return [{ json: { cmoReport, founderReport, memoryPayload } }];
